#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    const int iteration,
    __global const int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuDst,
    const int cols,
    const int rows,
    const int startStep,
    const int borderCols,
    const int halo,
    __local int* prev,
    __local int* result,
    __global int* outputBuffer)
{
    (void)rows;
    (void)borderCols;
    (void)halo;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_group_id(0) != 0)
        return;

    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);

    __global int* in = gpuSrc;
    __global int* out = gpuDst;

    for (int t = 0; t < iteration; t++) {
        const int wallOffset = (startStep + t) * cols;

        for (int n = lid; n < cols; n += lsize) {
            int minv = in[n];
            if (n > 0)
                minv = MIN(minv, in[n - 1]);
            if (n < cols - 1)
                minv = MIN(minv, in[n + 1]);
            out[n] = gpuWall[wallOffset + n] + minv;
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        __global int* tmp = in;
        in = out;
        out = tmp;
    }

    if ((iteration & 1) == 0) {
        for (int n = lid; n < cols; n += lsize) {
            gpuDst[n] = gpuSrc[n];
        }
    }
}
